body.raw:
{
  "key": "new_dashboard",
  "name": "New Dashboard",
  "description": "Roll out the redesigned dashboard",
  "flag_kind": "experiment",
  "type": "select",
  "default_value": "control",
  "options": ["control", "variant_a"],
  "variants": [
    {
      "key": "control",
      "name": "Control",
      "value": "control",
      "payload": { "theme": "legacy" }
    },
    {
      "key": "variant_a",
      "name": "Variant A",
      "value": "variant_a",
      "payload": { "theme": "modern" }
    }
  ],
  "default_variant_key": "control"
}

{
  "flag_id": "{{flag_id}}",
  "environment_key": "production",
  "title": "Promote premium rollout",
  "description": "Increase premium rollout in production",
  "base_snapshot_checksum": "{{snapshot_checksum}}",
  "desired_config": {
    "default_variant_key": "control",
    "rules": [
      {
        "name": "Premium rollout",
        "segment_keys": ["{{segment_key}}"],
        "conditions": [],
        "percentage": 75,
        "bucketing_key": "key",
        "serve": {
          "variant_key": "variant_a"
        }
      }
    ]
  }
}
